use actix_web::{web, App, HttpServer, HttpResponse, Responder};
use std::path::{Path, PathBuf};
use std::fs;

async fn serve_file(web::Path(filename): web::Path<String>) -> impl Responder {
    let uploads_dir = Path::new("uploads");
    let file_path = uploads_dir.join(&filename);

    // Validate the file path to prevent path traversal vulnerabilities
    if !file_path.starts_with(uploads_dir) {
        return HttpResponse::Forbidden().body("Access denied");
    }

    match fs::read(&file_path) {
        Ok(contents) => HttpResponse::Ok().body(contents),
        Err(_) => HttpResponse::NotFound().body("File not found"),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/files/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}